"use client";

import { useState, useCallback, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { triggerShake, getRandomEncourage, getRandomComplete } from "@/lib/learningMessages";

// ===== 阶段类型 =====
type Phase = "ruler" | "divide" | "position" | "done";

// ===== 定位题 =====
const POSITION_QS = [
  { target: 0.3, label: "0.3 \u5728\u54ea\u91cc\uff1f" },
  { target: 0.7, label: "0.7 \u5728\u54ea\u91cc\uff1f" },
  { target: 0.5, label: "0.5 \u5728\u54ea\u91cc\uff1f" },
] as const;

// ===== SVG 尺子 / 数轴参数 =====
const BAR_WIDTH = 480;
const BAR_HEIGHT = 60;
const BAR_PAD_X = 40;
const BAR_PAD_Y = 20;
const TOTAL_TICKS = 10;

function tickToX(tick: number): number {
  return BAR_PAD_X + (tick / TOTAL_TICKS) * BAR_WIDTH;
}

export default function CountPage() {
  const [phase, setPhase] = useState<Phase>("ruler");
  const [divided, setDivided] = useState(false);
  const [currentPosQ, setCurrentPosQ] = useState(0);
  const [posSolved, setPosSolved] = useState<boolean[]>([false, false, false]);
  const [highlightedTicks, setHighlightedTicks] = useState<number>(0);
  const [encourageMsg, setEncourageMsg] = useState("");
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const allPosDone = posSolved.every(Boolean);
  const currentTarget = POSITION_QS[currentPosQ].target;

  // ===== 阶段 1: 分成10份 =====
  const handleDivide = () => {
    if (divided) return;
    setDivided(true);
  };

  // ===== 阶段 2: 点击数轴定位 =====
  const handleAxisClick = useCallback(
    (e: React.MouseEvent<SVGSVGElement>) => {
      if (phase !== "position") return;
      if (posSolved[currentPosQ]) return;

      const svgEl = e.currentTarget;
      const rect = svgEl.getBoundingClientRect();
      const scaleX = (BAR_WIDTH + BAR_PAD_X * 2) / rect.width;
      const clickX = (e.clientX - rect.left) * scaleX;
      const tickVal = ((clickX - BAR_PAD_X) / BAR_WIDTH) * TOTAL_TICKS;

      // 判断是否接近目标刻度 (允许 +/-0.5 格的误差)
      if (Math.abs(tickVal - currentTarget * 10) <= 0.8) {
        const newSolved = [...posSolved];
        newSolved[currentPosQ] = true;
        setPosSolved(newSolved);
        setHighlightedTicks((prev) => prev + Math.round(currentTarget * 10));
        setEncourageMsg("");
      } else {
        const qEl = document.getElementById("position-question-box");
        triggerShake(qEl);
        setEncourageMsg(getRandomEncourage());
      }
    },
    [phase, currentPosQ, currentTarget, posSolved]
  );

  const nextStep = getNextStep("decimal", "count");

  return (
    <StepShell topicId="decimal" stepId="count">
      {/* ===== 阶段 1: 认识 0.1 ===== */}
      {(phase === "ruler" || phase === "divide") && (
        <div className="space-y-6">
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
              \u8fd9\u662f\u4e00\u6761 1 \u7c73\u957f\u7684\u5c3a\u5b50
            </p>

            {/* 尺子 SVG */}
            <div className="flex justify-center overflow-x-auto">
              <svg
                viewBox={`0 0 ${BAR_WIDTH + BAR_PAD_X * 2} ${BAR_HEIGHT + BAR_PAD_Y * 2}`}
                className="w-full max-w-lg"
              >
                {/* 尺子主体 */}
                <rect
                  x={BAR_PAD_X}
                  y={BAR_PAD_Y}
                  width={BAR_WIDTH}
                  height={BAR_HEIGHT}
                  rx={6}
                  fill="var(--bg-soft)"
                  stroke="var(--border)"
                  strokeWidth={2}
                />

                {/* 左端标注 0 */}
                <text
                  x={BAR_PAD_X}
                  y={BAR_PAD_Y + BAR_HEIGHT + 16}
                  textAnchor="middle"
                  fill="var(--text-secondary)"
                  fontSize={13}
                  fontWeight="bold"
                >
                  0
                </text>

                {/* 右端标注 1 米 */}
                <text
                  x={BAR_PAD_X + BAR_WIDTH}
                  y={BAR_PAD_Y + BAR_HEIGHT + 16}
                  textAnchor="middle"
                  fill="var(--text-secondary)"
                  fontSize={13}
                  fontWeight="bold"
                >
                  1 \u7c73
                </text>

                {/* 分成10份后的刻度和标注 */}
                {divided &&
                  Array.from({ length: TOTAL_TICKS + 1 }).map((_, i) => {
                    const x = tickToX(i);
                    return (
                      <g key={`tick-${i}`}>
                        <line
                          x1={x}
                          y1={BAR_PAD_Y}
                          x2={x}
                          y2={BAR_PAD_Y + (i === 0 || i === TOTAL_TICKS ? BAR_HEIGHT : BAR_HEIGHT * 0.5)}
                          stroke={i <= highlightedTicks ? "var(--accent)" : "var(--text-muted)"}
                          strokeWidth={1.5}
                        />
                        {/* 中间刻度标签 */}
                        {i > 0 && i < TOTAL_TICKS && (
                          <text
                            x={x}
                            y={BAR_PAD_Y - 4}
                            textAnchor="middle"
                            fill={i <= highlightedTicks ? "var(--accent)" : "var(--text-muted)"}
                            fontSize={10}
                          >
                            0.{i}
                          </text>
                        )}
                        {/* 高亮色块 */}
                        {i < TOTAL_TICKS && i < highlightedTicks && (
                          <rect
                            x={tickToX(i)}
                            y={BAR_PAD_Y}
                            width={BAR_WIDTH / TOTAL_TICKS}
                            height={BAR_HEIGHT}
                            fill="var(--accent)"
                            opacity={0.25}
                            rx={i === 0 ? 6 : 0}
                          />
                        )}
                      </g>
                    );
                  })}
              </svg>
            </div>

            {/* 提示文字 */}
            {phase === "ruler" && (
              <div className="mt-6 flex justify-center">
                <button
                  onClick={() => {
                    handleDivide();
                    setPhase("divide");
                  }}
                  className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                >
                  \u5206\u621010\u4efd \u2192
                </button>
              </div>
            )}

            {phase === "divide" && (
              <div className="mt-4 animate-float-in text-center">
                <p className="text-sm font-medium text-[var(--accent)]">
                  1\u7c73\u5e73\u5747\u5206\u621010\u4efd\uff0c\u6bcf\u4efd\u662f
                  <span className="mx-1 text-lg font-extrabold">0.1\u7c73</span>
                </p>
                <p className="mt-1 text-sm text-[var(--text-secondary)]">
                  \u4e5f\u5c31\u662f 1 \u5206\u7c73
                </p>
                <div className="mt-6">
                  <button
                    onClick={() => setPhase("position")}
                    className="rounded-full bg-[var(--primary)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  >
                    \u6570\u4e00\u6570 \u2192
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* ===== 阶段 2: 数一数 ===== */}
      {phase === "position" && (
        <div className="space-y-6">
          {/* 题目进度 */}
          <div className="flex items-center justify-center gap-2">
            {POSITION_QS.map((_, i) => (
              <div
                key={i}
                className={`h-2.5 w-8 rounded-full transition-all ${
                  i === currentPosQ
                    ? "bg-[var(--signal-focus)]"
                    : posSolved[i]
                    ? "bg-[var(--signal-confirmed)]"
                    : "bg-[var(--border)]"
                }`}
                style={{ opacity: posSolved[i] ? 0.6 : i === currentPosQ ? 1 : 0.4 }}
              />
            ))}
          </div>

          {/* 数轴 */}
          <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
              \u70b9\u51fb\u6570\u8f74\u4e0a\u7684\u4f4d\u7f6e
            </p>
            <div className="flex justify-center overflow-x-auto">
              <svg
                id="position-axis"
                viewBox={`0 0 ${BAR_WIDTH + BAR_PAD_X * 2} ${BAR_HEIGHT + BAR_PAD_Y * 2 + 20}`}
                className="w-full max-w-lg cursor-pointer"
                onClick={handleAxisClick}
              >
                {/* 主轴线 */}
                <line
                  x1={BAR_PAD_X}
                  y1={BAR_PAD_Y + 20}
                  x2={BAR_PAD_X + BAR_WIDTH}
                  y2={BAR_PAD_Y + 20}
                  stroke="var(--text-muted)"
                  strokeWidth={2}
                />
                {/* 箭头 */}
                <polygon
                  points={`${BAR_PAD_X + BAR_WIDTH + 8},${BAR_PAD_Y + 20} ${BAR_PAD_X + BAR_WIDTH},${BAR_PAD_Y + 15} ${BAR_PAD_X + BAR_WIDTH},${BAR_PAD_Y + 25}`}
                  fill="var(--text-muted)"
                />
                {/* 刻度 */}
                {Array.from({ length: TOTAL_TICKS + 1 }).map((_, i) => {
                  const x = tickToX(i);
                  const isMajor = i === 0 || i === 5 || i === TOTAL_TICKS;
                  return (
                    <g key={`pos-tick-${i}`}>
                      <line
                        x1={x}
                        y1={BAR_PAD_Y + 20 - (isMajor ? 10 : 5)}
                        x2={x}
                        y2={BAR_PAD_Y + 20 + (isMajor ? 10 : 5)}
                        stroke="var(--text-muted)"
                        strokeWidth={isMajor ? 1.5 : 0.8}
                      />
                      <text
                        x={x}
                        y={BAR_PAD_Y + 44}
                        textAnchor="middle"
                        fill="var(--text-secondary)"
                        fontSize={11}
                      >
                        {isMajor ? (i / TOTAL_TICKS).toFixed(1) : `${i}`}
                      </text>
                      {/* 已答对的高亮格子 */}
                      {i < TOTAL_TICKS && i < highlightedTicks && (
                        <rect
                          x={tickToX(i)}
                          y={BAR_PAD_Y + 8}
                          width={BAR_WIDTH / TOTAL_TICKS}
                          height={24}
                          fill="var(--accent)"
                          opacity={0.25}
                          rx={2}
                        />
                      )}
                    </g>
                  );
                })}
                {/* 已找到的正确点标记 */}
                {posSolved.map((solved, qIdx) =>
                  solved ? (
                    <g key={`found-${qIdx}`}>
                      <circle
                        cx={tickToX(POSITION_QS[qIdx].target * 10)}
                        cy={BAR_PAD_Y + 20}
                        r={8}
                        fill="var(--signal-confirmed)"
                        opacity={0.8}
                      />
                      <text
                        x={tickToX(POSITION_QS[qIdx].target * 10)}
                        y={BAR_PAD_Y + 6}
                        textAnchor="middle"
                        fill="var(--signal-confirmed)"
                        fontSize={11}
                        fontWeight="bold"
                      >
                        {POSITION_QS[qIdx].target.toFixed(1)}
                      </text>
                    </g>
                  ) : null
                )}
              </svg>
            </div>
          </div>

          {/* 当前题目 */}
          {!allPosDone && (
            <div
              id="position-question-box"
              className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
            >
              <p className="mb-1 text-center text-sm text-[var(--text-muted)]">
                \u7b2c {currentPosQ + 1} \u9898
              </p>
              <p className="text-center text-lg font-semibold text-[var(--text)]">
                {POSITION_QS[currentPosQ].label}
              </p>
              {posSolved[currentPosQ] && (
                <p className="mt-3 text-center text-sm font-medium text-[var(--signal-success)] animate-float-in">
                  \u2714 \u627e\u5bf9\u4e86\uff01{POSITION_QS[currentPosQ].target.toFixed(1)} \u5728\u8fd9\u91cc\uff01
                </p>
              )}
              {encourageMsg && (
                <p className="mt-3 text-center text-sm text-[var(--text-secondary)]">
                  \ud83d\udca1 {encourageMsg}
                </p>
              )}
              {/* 下一题 */}
              {posSolved[currentPosQ] && currentPosQ < POSITION_QS.length - 1 && (
                <div className="mt-4 flex justify-center">
                  <button
                    onClick={() => {
                      setCurrentPosQ((p) => p + 1);
                      setEncourageMsg("");
                    }}
                    className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  >
                    \u4e0b\u4e00\u9898 \u2192
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* ===== 完成卡片 ===== */}
      {phase === "position" && allPosDone && (
        <div className="mt-6 animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
          <div className="text-4xl mb-2">\ud83c\udf1f</div>
          <p className="text-lg font-semibold text-[var(--text)]">
            {completeMsg}
          </p>
          <p className="mt-2 text-sm text-[var(--text-secondary)]">
            1\u7c73\u5206\u621010\u4efd\uff0c\u6bcf\u4efd 0.1 \u7c73\uff0c\u4f60\u5df2\u7ecf\u80fd\u5728\u6570\u8f74\u4e0a\u627e\u5230\u5c0f\u6570\u7684\u4f4d\u7f6e\u4e86\uff01
          </p>
          <div className="mt-6 flex justify-center gap-4">
            <button
              onClick={() => {
                setPhase("ruler");
                setDivided(false);
                setCurrentPosQ(0);
                setPosSolved([false, false, false]);
                setHighlightedTicks(0);
                setEncourageMsg("");
              }}
              className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
            >
              \u518d\u7ec3\u4e00\u904d
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                \u4e0b\u4e00\u6b65\uff1a{nextStep.label} \u2192
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
